 1	import React, { FC, FormEvent } from 'react';
 2	import { Updater } from 'use-immer';
 3	
 4	import {
 5	  Button,
 6	  ButtonVariant,
 7	  Flex,
 8	  FlexItem,
 9	  PageSection,
10	  PageSectionVariants,
11	  TextInput,
12	  Title,
13	} from '@patternfly/react-core';
14	import { MinusCircleIcon } from '@patternfly/react-icons';
15	import { V1NodeNetworkConfigurationPolicy } from '@types';
16	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
17	import { OVN_BRIDGE_MAPPINGS } from '@utils/ovn/constants';
18	
19	type PolicyFormOVSBridgeMappingExpandableProps = {
20	  policy: V1NodeNetworkConfigurationPolicy;
21	  setPolicy: Updater<V1NodeNetworkConfigurationPolicy>;
22	};
23	
24	const PolicyFormOVSBridgeMappingExpandable: FC<PolicyFormOVSBridgeMappingExpandableProps> = ({
25	  policy,
26	  setPolicy,
27	}) => {
28	  const { t } = useNMStateTranslation();
29	
30	  const onChange =
31	    (index: number, field: string) => (_: FormEvent<HTMLInputElement>, value: string) => {
32	      setPolicy((draftPolicy) => {
33	        draftPolicy.spec.desiredState.ovn[OVN_BRIDGE_MAPPINGS][index] = {
34	          ...draftPolicy.spec.desiredState.ovn[OVN_BRIDGE_MAPPINGS][index],
35	          [field]: value,
36	        };
37	      });
38	    };
39	
40	  const onRemove = (index: number) => {
41	    setPolicy((draftPolicy) => {
42	      draftPolicy.spec.desiredState.ovn[OVN_BRIDGE_MAPPINGS].splice(index, 1);
43	    });
44	  };
45	
46	  return policy?.spec?.desiredState?.ovn?.[OVN_BRIDGE_MAPPINGS]?.map((bridgeMapping, index) => {
47	    return (
48	      <PageSection variant={PageSectionVariants.light} key={index}>
49	        <Flex alignItems={{ default: 'alignItemsFlexEnd' }} marginWidth={20}>
50	          <FlexItem grow={{ default: 'grow' }} spacer={{ default: 'spacer4xl' }}>
51	            <Title headingLevel="h6" size="md">
52	              {t('OVN localnet name')}
53	            </Title>
54	            <TextInput value={bridgeMapping?.localnet} onChange={onChange(index, 'localnet')} />
55	          </FlexItem>
56	          <FlexItem grow={{ default: 'grow' }}>
57	            <Title headingLevel="h6" size="md">
58	              {t('OVS bridge name')}
59	            </Title>
60	            <TextInput value={bridgeMapping?.bridge} onChange={onChange(index, 'bridge')} />
61	          </FlexItem>
62	          <FlexItem>
63	            <Button
64	              variant={ButtonVariant.plain}
65	              aria-label={t('Remove')}
66	              onClick={() => onRemove(index)}
67	            >
68	              <MinusCircleIcon />
69	            </Button>
70	          </FlexItem>
71	        </Flex>
72	      </PageSection>
73	    );
74	  });
75	};
76	
77	export default PolicyFormOVSBridgeMappingExpandable;

